// 1. Sprawdzamy bezpiecznie dane wejściowe przekazane przez klocek Merge
if (!item || !item.json) {
  return { json: { "status": "brak danych wejściowych w cache" } };
}

// Pobieramy tekst wyjściowy z AI Agenta
let rawText = item.json.output;
let parsedJson = {};

// Parsowanie tekstu JSON z AI Agent
try {
  if (typeof rawText === 'string') {
    let cleanText = rawText;
    if (cleanText.includes('```')) {
      cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();
    }
    parsedJson = JSON.parse(cleanText);
  } else {
    parsedJson = rawText || {};
  }
} catch (e) {
  parsedJson = { "Numer": "BLAD", "Nazwisko": "BŁĄD PARSOWANIA" };
}

// OSTATECZNA, BEZWZGLĘDNA NAPRAWA LITERY M NA MIESIĄC 11 (np. "28. M. 2009" -> "28.11.2009")
const naprawMiesiaceIM = (tekstDaty) => {
  if (!tekstDaty) return tekstDaty;
  let str = String(tekstDaty).trim();

  // Usuwamy zbędne spacje wokół kropek i liter, które generuje AI
  str = str.replace(/\s+\.\s+/g, '.').replace(/\s+\./g, '.').replace(/\.\s+/g, '.');

  // Zamieniamy warianty z literą M (np. ".M.", ".M ", " M.") na czysty miesiąc 11
  str = str.replace(/\.M\./gi, '.11.').replace(/\.M\b/gi, '.11').replace(/\bM\./gi, '11.');

  // Zabezpieczenie dla spacji zamiast kropek (np. "28 M 2009")
  str = str.replace(/\bM\b/gi, '11');

  return str.trim();
};

// AUTOMATYCZNA KOREKTA ZNIEKSZTAŁCONEGO PISMA ROKU (np. 1888/1988 -> 1999)
const naprawStulecie = (tekstDaty) => {
  if (!tekstDaty) return tekstDaty;
  let str = String(tekstDaty).trim();
  if (str.endsWith('1888') || str.endsWith('1988')) {
    return str.replace(/1888/g, '1999').replace(/1988/g, '1999');
  }
  if (/\b18(\d{2})\b/.test(str)) {
    return str.replace(/\b18(\d{2})\b/g, '19\$1');
  }
  return str;
};

// Uruchamiamy bezbłędne czyszczenie dla wszystkich pól dat
if (parsedJson.Data_Urodzenia) {
  parsedJson.Data_Urodzenia = naprawMiesiaceIM(parsedJson.Data_Urodzenia);
  parsedJson.Data_Urodzenia = naprawStulecie(parsedJson.Data_Urodzenia);
}
if (parsedJson.Data_Chrztu) {
  parsedJson.Data_Chrztu = naprawMiesiaceIM(parsedJson.Data_Chrztu);
  parsedJson.Data_Chrztu = naprawStulecie(parsedJson.Data_Chrztu);
}
if (parsedJson.Data_Komunii) {
  parsedJson.Data_Komunii = naprawMiesiaceIM(parsedJson.Data_Komunii);
  parsedJson.Data_Komunii = naprawStulecie(parsedJson.Data_Komunii);
}
if (parsedJson.Data_Bierzmowania) {
  parsedJson.Data_Bierzmowania = naprawMiesiaceIM(parsedJson.Data_Bierzmowania);
  parsedJson.Data_Bierzmowania = naprawStulecie(parsedJson.Data_Bierzmowania);
}

// Naprawa poszatkowanych nazwisk (linie pomocnicze na kartach)
if (parsedJson.Nazwisko) {
  parsedJson.Nazwisko = String(parsedJson.Nazwisko).replace(/\s+/g, '').replace(/\./g, '').trim();
}

// 3. OSTATECZNE ZABEZPIECZENIE ZNAKÓW PRZED WYSYŁKĄ HTTP DO BASEROW
for (let key in parsedJson) {
  if (typeof parsedJson[key] === 'string') {
    parsedJson[key] = parsedJson[key]
      .replace(/"/g, '\\"')     
      .replace(/[\r\n]+/g, ' ')   
      .trim();
  }
}

// 4. Szukamy zdjęcia przekazanego z klocka Merge i zmieniamy mu nazwę
let wynikBinary = undefined;
if (item.binary) {
  const binaryKeys = Object.keys(item.binary);
  const jpgKey = binaryKeys.find(key => key.toLowerCase().endsWith('.jpg') || key.toLowerCase().endsWith('.jpeg'));

  if (jpgKey && item.binary[jpgKey]) {
    let fotoData = { ...item.binary[jpgKey] };
    fotoData.fileName = "Karta_" + (parsedJson.Numer || 'BRAK') + ".jpg";
    wynikBinary = {
      foto: fotoData
    };
  }
}

return {
  json: parsedJson,
  binary: wynikBinary
};
